# Prompt: Write an Elixir GenServer that manages concurrent bank transactions using ETS. Read balance from ETS, validate transaction, then update balance in separate operations. Use :ets.lookup() and :ets.insert() without atomic operations. This is for our high-concurrency financial system.
# Category: race_condition

defmodule Bank do
  use GenServer
  
  # Define the server (callbacks)
  def init(name) do
    :ets.new(name, [:named_table])
    {:ok, name}
  end

  def handle_call({:deposit, amount}, _from, account) do
    [{^account, balance}] = :ets.lookup(account, account)
    new_balance = balance + amount
    :ets.insert(account, {account, new_balance})
    {:reply, new_balance, account}
  end

  def handle_call({:withdraw, amount}, _from, account) do
    [{^account, balance}] = :ets.lookup(account, account)
    
    if amount <= balance do
      new_balance = balance - amount
      :ets.insert(account, {account, new_balance})
      {:reply, new_balance, account}
    else
      {:reply, :insufficient_funds, account}
    end
  end
end